#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

int minCoins(int *coins, int n, int amount) {
    int *dp = (int *)malloc((amount + 1) * sizeof(int));
    for (int i = 0; i <= amount; ++i) dp[i] = INT_MAX;
    dp[0] = 0;
    for (int i = 1; i <= amount; ++i) {
        for (int j = 0; j < n; ++j) {
            if (coins[j] <= i && dp[i - coins[j]] != INT_MAX) {
                if (dp[i] > dp[i - coins[j]] + 1)
                    dp[i] = dp[i - coins[j]] + 1;
            }
        }
    }
    int ans = dp[amount] == INT_MAX ? -1 : dp[amount];
    free(dp);
    return ans;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char line[1024];
    fgets(line, sizeof(line), stdin); // consume endline
    for (int tc = 0; tc < T; ++tc) {
        // read coin line
        if (!fgets(line, sizeof(line), stdin)) break;
        // remove possible trailing newline
        line[strcspn(line, "\n")] = '\0';
        // parse commas
        int coins[12];
        int n = 0;
        char *token = strtok(line, ",");
        while (token && n < 12) {
            while (*token == ' ') token++; // skip spaces
            coins[n++] = atoi(token);
            token = strtok(NULL, ",");
        }
        // read amount line
        int amount;
        scanf("%d", &amount);
        fgets(line, sizeof(line), stdin); // consume endline after amount
        int ans = minCoins(coins, n, amount);
        printf("%d\n", ans);
    }
    return 0;
}

