#include <bits/stdc++.h>
using namespace std;

int minCoins(const vector<int>& coins, int amount) {
    const int INF = 1e9;
    vector<int> dp(amount + 1, INF);
    dp[0] = 0;
    for (int i = 1; i <= amount; ++i) {
        for (int c : coins) {
            if (c <= i && dp[i - c] != INF) {
                dp[i] = min(dp[i], dp[i - c] + 1);
            }
        }
    }
    return dp[amount] == INF ? -1 : dp[amount];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; 
    if (!(cin >> T)) return 0;
    string dummy; getline(cin, dummy); // consume endline
    while (T--) {
        string coinLine; getline(cin, coinLine);
        vector<int> coins;
        string token;
        stringstream ss(coinLine);
        while (getline(ss, token, ',')) {
            // trim spaces
            size_t start = token.find_first_not_of(' ');
            if (start != string::npos) token = token.substr(start);
            if (!token.empty()) coins.push_back(stoi(token));
        }
        int amount; cin >> amount; getline(cin, dummy); // consume endline after amount
        cout << minCoins(coins, amount) << '\n';
    }
    return 0;
}

